export function getDrugInfo(name: string): PharmaEntry | null {
  const key = Object.keys(PHARMA_DB).find(k => k.toLowerCase() === name.toLowerCase() || name.toLowerCase().startsWith(k.toLowerCase()));
  return key ? PHARMA_DB[key] : null;
}

export interface ScientificAlert {
  id: string; severity: "critical"|"urgent"|"warning"|"info";
  category: string; title: string; detail: string;
  evidence: string; action: string; icon: string;
  description?: string; date?: string; type?: string;
}
export function generateClinicalAlerts(
  fev1Readings: FEV1Reading[],
  medications: CopdMedication[],
  adherencePct: number,
  labOrders: LabOrder[],
  patientProfile?: Record<string, unknown>,
): ScientificAlert[] {
  const alerts: ScientificAlert[] = [];
  const latestFEV1 = fev1Readings.at(-1);
  if (!latestFEV1) return alerts;
  const fev1Pct = latestFEV1.fev1Percent;

  if (fev1Pct < 30) alerts.push({ id:"gold4",severity:"critical",category:"GOLD Stage 4",title:`FEV1 ${fev1Pct}% — GOLD 4 (Very Severe)`,detail:"FEV1 <30% predicted indicates end-stage COPD. High risk of respiratory failure and cor pulmonale.",evidence:"GOLD 2024: FEV1 <30% predicted = GOLD 4",action:"Assess for LTOT, lung volume reduction, transplant evaluation. Advance care planning.",icon:"🚨"});
  if (fev1Pct < 50) alerts.push({ id:"gold3",severity:"urgent",category:"GOLD Stage 3",title:`FEV1 ${fev1Pct}% — GOLD 3 (Severe)`,detail:"FEV1 30-50%. Consider triple therapy if exacerbations.",evidence:"GOLD 2024: FEV1 30-50% = GOLD 3",action:"Optimise bronchodilator therapy. Assess for pulmonary rehab.",icon:"⚠️"});

  const last6 = fev1Readings.slice(-6);
  if (last6.length >= 3) {
    const decline = last6[0].fev1 - last6[last6.length-1].fev1;
    const months = (last6[last6.length-1].recordedAt.getTime() - last6[0].recordedAt.getTime()) / (30*86400000);
    if (months > 0 && (decline/months) > 0.06) alerts.push({ id:"fev1_decline",severity:"warning",category:"Accelerated FEV1 Decline",title:`FEV1 Declining >60 mL/yr (est. ${Math.round(decline/months*100)/100} L/yr)`,detail:"Accelerated FEV1 decline marker of disease progression.",evidence:"GOLD 2024: Normal ~30 mL/yr; >60 mL/yr accelerated",action:"Verify smoking cessation. Optimise therapy. Consider α1-AT testing.",icon:"📉"});
  }

  const catScore = (patientProfile?.catScore as number) ?? 0;
  if (catScore >= 20) alerts.push({ id:"cat_high",severity:"urgent",category:"High Symptom Burden",title:`CAT Score ${catScore} — Very High`,detail:"CAT ≥20 indicates very high symptom burden.",evidence:"GOLD 2024: CAT ≥10 = high symptom burden",action:"Escalate therapy. Urgent pulmonary rehab referral.",icon:"😤"});
  else if (catScore >= 10) alerts.push({ id:"cat_mod",severity:"warning",category:"Moderate Symptoms",title:`CAT Score ${catScore} — High Symptom Burden`,detail:"CAT ≥10 indicates significant symptom impact.",evidence:"GOLD 2024: CAT ≥10 threshold",action:"Consider LAMA/LABA or ICS/LABA escalation. Pulmonary rehab.",icon:"😮‍💨"});

  const exac = (patientProfile?.exacerbations as number) ?? 0;
  const hosp = (patientProfile?.hospitalizations as number) ?? 0;
  if (exac > 2) alerts.push({ id:"freq_exac",severity:"urgent",category:"Frequent Exacerbator",title:`${exac} Exacerbations in Past Year`,detail:"≥2 exacerbations/year = high risk Group E.",evidence:"GOLD 2024: ≥2 exacerbations/year = high risk",action:"Triple therapy. Consider roflumilast if chronic bronchitis. Pulmonary rehab.",icon:"🔁"});
  if (hosp > 0) alerts.push({ id:"hosp",severity:"critical",category:"Hospitalisation",title:`${hosp} Hospitalisation(s) for COPD`,detail:"Any hospitalisation = high mortality risk.",evidence:"GOLD 2024: Hospitalisation = high mortality",action:"Triple therapy with ICS. Pulmonary rehab post-discharge. Assess for LTOT/NIV.",icon:"🏥"});

  const spo2 = latestFEV1.spo2;
  if (spo2 !== undefined) {
    if (spo2 < 88) alerts.push({ id:"spo2_crit",severity:"critical",category:"Severe Hypoxaemia",title:`SpO₂ ${spo2}% — Severe Hypoxaemia`,detail:"SpO₂ <88% requires immediate LTOT assessment.",evidence:"ATS/ERS: SpO₂ <88% = hypoxaemia",action:"Check ABG. Initiate O₂ (target SpO₂ 88-92%). Assess for LTOT.",icon:"🫁"});
    else if (spo2 < 92) alerts.push({ id:"spo2_low",severity:"warning",category:"Borderline Hypoxaemia",title:`SpO₂ ${spo2}% — Mild Hypoxaemia`,detail:"Consider ABG to rule out CO2 retention.",evidence:"ATS/ERS: SpO₂ target 88-92% in COPD",action:"Check ABG. Assess exercise desaturation. Review LTOT eligibility.",icon:"🫁"});
  }

  if (fev1Readings.length > 0) {
    const monthsSince = (Date.now() - fev1Readings[fev1Readings.length-1].recordedAt.getTime())/(30*86400000);
    if (monthsSince > 12) alerts.push({ id:"spiro_due",severity:"warning",category:"Spirometry Due",title:`No Spirometry in ${Math.round(monthsSince)} Months`,detail:"Annual spirometry recommended.",evidence:"GOLD 2024: Annual spirometry",action:"Schedule spirometry.",icon:"📊"});
  }

  if (adherencePct < 50) alerts.push({ id:"adh",severity:"urgent",category:"Low Adherence",title:`Adherence: ${adherencePct}%`,detail:"Poor adherence ↑ exacerbations and mortality.",evidence:"Systematic review: non-adherence 25-60% in COPD",action:"Simplify regimen. Address barriers. Consider single-inhaler triple therapy.",icon:"📅"});

  if (patientProfile?.pulmonaryRehab === false) alerts.push({ id:"rehab",severity:"warning",category:"Rehab Needed",title:"No Pulmonary Rehabilitation Referral",detail:"Pulmonary rehab is cornerstone of COPD management (Grade A).",evidence:"GOLD 2024: Pulmonary rehab strongly recommended",action:"Refer to pulmonary rehabilitation program.",icon:"🏃"});

  if (patientProfile?.vaccinesUpToDate === false) alerts.push({ id:"vax",severity:"info",category:"Vaccinations Due",title:"Vaccinations Due",detail:"Annual influenza and pneumococcal vaccines recommended.",evidence:"GOLD 2024: Immunisations recommended",action:"Administer influenza, pneumococcal, COVID-19 vaccines.",icon:"💉"});

  if (patientProfile?.smokingStatus === "current") alerts.push({ id:"smoking",severity:"urgent",category:"Current Smoker",title:"Patient is a Current Smoker",detail:"Smoking cessation slows FEV1 decline — most effective intervention.",evidence:"GOLD 2024: Smoking cessation is the most important intervention",action:"Offer counselling + NRT/varenicline/bupropion. Set quit date.",icon:"🚬"});

  const lastVisit = patientProfile?.lastVisitDate as string;
  if (lastVisit) {
    const monthsSince = (Date.now()-new Date(lastVisit).getTime())/(30*86400000);
    if (monthsSince > 6) alerts.push({ id:"followup",severity:"warning",category:"Follow-up Overdue",title:`No Follow-up in ${Math.round(monthsSince)} Months`,detail:"COPD patients reviewed every 6 months.",evidence:"GOLD 2024: Review every 6 months",action:"Schedule follow-up. Review symptoms/spirometry/inhaler technique.",icon:"📅"});
  }

  if (patientProfile?.corPulmonale === true) alerts.push({ id:"cor_pulm",severity:"critical",category:"Cor Pulmonale",title:"Cor Pulmonale — Right Heart Failure",detail:"Advanced COPD with pulmonary hypertension. High mortality.",evidence:"GOLD 2024: Cor pulmonale = poor prognosis",action:"Optimise LTOT. Echocardiogram. Diuretics. Advance care planning.",icon:"❤️"});

  return alerts;
}

export interface FEV1Reading {
  id: string; fev1: number; fev1Percent: number; fvc?: number;
  fev1Fvc?: number; dlco?: number; recordedAt: Date;
  spo2?: number; notes?: string; catScore?: number;
  mrcGrade?: number; source?: string;
  value?: number; predicted?: number;
}

export interface CopdMedication {
  id: string; drug: string; medication?: string;
  dose: string; dosage?: string; unit: string; frequency: string;
  drugClass: string; status: "active"|"stopped"|"paused";
  startDate: string; endDate?: string; indication?: string;
  route?: string; instructions?: string; warnings?: string;
  refills?: number; duration?: string; notes?: string;
  changeHistory?: CopdDoseChange[];
  drugName?: string;
  patientId?: string;
  toolType?: string;
  change?: string;
  createdAt?: string;
  doctorName?: string;
}

export interface CopdDoseChange {
  date: string; changeType: "started"|"dose_increase"|"dose_decrease"|"stopped"|"paused"|"restarted";
  previousDose?: string; newDose?: string; changedBy: string; reason?: string;
}

export interface PatientSummary {
  id: string; name: string; age?: number; gender?: string; sex?: string; email?: string;
  phone?: string; mrn?: string; universalId?: string; diagnosis?: string; riskLevel?: string;
  lastVisit?: string; nextReview?: string;
  latestFEV1?: number; latestFEV1Pct?: number; latestAt?: Date;
  totalReadings?: number; latestSpo2?: number;
  goldStage?: string; catScore?: number; exacerbations?: number; mrcScore?: number;
  copdDiagnosis?: boolean; doctorId?: string;
  [key: string]: any;
}
export interface Exacerbation { id?: string; date?: string; severity?: string; description?: string; admitted?: boolean; }
export interface CATScore { id?: string; score: number; date: string; notes?: string; }
export interface MRCScores { id?: string; score: number; date: string; }
export interface Referral { id: string; specialty: string; reason: string; priority: "routine"|"urgent"|"emergency"; date: string; status: "pending"|"completed"|"cancelled"; patientName: string; patientId: string; doctorId?: string; doctorName?: string; }

export interface Alert { id: string; trigger: string; actions: string[]; createdAt: string; doctorNote?: string; category?: string; history: { date: string; message: string }[]; type?: string; date?: string; severity?: string; title?: string; description?: string; }
export interface Complication { name: string; active: boolean; note?: string; date?: string; }
export interface LifestyleItem { name: string; active: boolean; grade: "Good"|"Moderate"|"Poor"; updatedAt?: string; }
export interface LabOrder { name: string; result?: string|null; orderedAt?: string; type?: "lab"|"imaging"; status?: string; study?: string; modality?: string; bodyPart?: string; urgency?: string; ordered?: boolean; date?: string; patientId?: string; orderedBy?: string; }
export interface ClinicalNote { id?: string; date: string; cc?: string; hpi?: string; exam?: string; investigations?: string; assessment?: string; plan?: string; diagnoses?: string[]; followUps?: string[]; isLocked?: boolean; lastEditedAt?: string; doctorId?: string; doctorName?: string; visitType?: string; vitals?: Record<string, string>; }
export interface TimelineEvent { id: string; date: string; type: "visit"|"med"|"alert"|"reading"|"note"|"lab"|"exacerbation"|"hospitalization"|"er_visit"|"pft"|"vaccination"|"med_change"|"smoking_cessation"|"pulmonary_rehab"|"other"; icon?: string; title?: string; description?: string; }
export interface Message { id?: string; from?: "doctor"|"patient"; sentBy?: "doctor"|"patient"; senderId?: string; senderName?: string; senderRole?: string; time?: string; date?: string; text: string; read?: boolean; status?: string; threadId?: string; timestamp?: Date; priority?: "normal"|"urgent"; }
export interface AdherenceMap { [medId: string]: { [date: string]: boolean }; }
export interface ChartPoint { date: string; isoDate: string; fev1: number; fev1Percent: number; fvc?: number; fev1Fvc?: number; category: string; }
export interface EducationTopic { id: string; title: string; content: string; keyPoints: string[]; category: string; duration: string; sentAt?: string; acknowledged?: boolean; }

export const EDUCATION_TOPICS: EducationTopic[] = [
  { id:"copd_basics",title:"What is COPD?",content:"COPD is a chronic lung disease that makes it hard to breathe. It includes emphysema and chronic bronchitis. While there is no cure, treatment helps you breathe easier and reduce exacerbations.",keyPoints:["COPD is a chronic progressive lung disease","Main types: emphysema and chronic bronchitis","Smoking is the leading cause (80-90%)","Not curable but manageable","Early treatment slows progression"],category:"Foundation",duration:"5 min"},
  { id:"spirometry",title:"Understanding Spirometry",content:"Spirometry measures how much air you can breathe out and how fast. FEV1 percent predicted tells us severity: ≥80% = GOLD 1 (Mild), 50-79% = GOLD 2 (Moderate), 30-49% = GOLD 3 (Severe), <30% = GOLD 4 (Very Severe).",keyPoints:["FEV1 = air blown out in 1 second","FVC = total air blown out","FEV1/FVC <0.7 confirms COPD","GOLD stages 1-4 based on FEV1%","Annual spirometry tracks progression"],category:"Monitoring",duration:"4 min"},
  { id:"smoking_cessation",title:"Smoking Cessation",content:"Quitting smoking is the single most effective treatment for COPD. It slows lung function decline, reduces symptoms, and lowers exacerbation risk.",keyPoints:["Smoking causes 80-90% of COPD","Quitting slows FEV1 decline","NRT doubles quit success rates","Varenicline is most effective","Set a quit date"],category:"Lifestyle",duration:"6 min"},
  { id:"inhaler_technique",title:"Inhaler Technique",content:"Up to 80% of patients use their inhaler incorrectly. Each device has specific steps. Using a spacer with pMDI significantly improves lung deposition.",keyPoints:["Different devices have DIFFERENT techniques","Shake pMDI inhalers before use","Breathe OUT fully before inhaling","Hold breath for 10 seconds per puff","Rinse mouth after ICS inhalers"],category:"Medications",duration:"5 min"},
  { id:"breathlessness",title:"Managing Breathlessness",content:"Dyspnoea is the most distressing COPD symptom. Manage with pursed-lip breathing, positioning (leaning forward), and pacing activities. Pulmonary rehabilitation is most effective.",keyPoints:["Pursed-lip breathing technique","Tripod position for relief","Pace yourself — break tasks into steps","Use a rollator to reduce energy","Pulmonary rehab is #1 treatment"],category:"Symptoms",duration:"5 min"},
  { id:"pulmonary_rehab",title:"Pulmonary Rehabilitation",content:"Structured program of exercise and education that improves breathlessness, exercise capacity, and quality of life. Reduces hospitalisations.",keyPoints:["Exercise + education = reduced symptoms","Strongest evidence for reducing readmissions","Improves exercise tolerance 30-50%","Includes strength + aerobic training","Ask your doctor for a referral"],category:"Treatment",duration:"5 min"},
  { id:"exacerbations",title:"Recognising COPD Exacerbations",content:"An exacerbation is sudden worsening of symptoms. Triggers: respiratory infections, air pollution, non-adherence. Mild cases managed at home; severe needs hospital.",keyPoints:["Cardinal signs: ↑ breathlessness, ↑ sputum volume, ↑ purulence","Use your Action Plan","Increase reliever inhaler as needed","Start oral prednisolone 30-40mg for 5 days","Start antibiotics if sputum purulent","SEEK help for severe breathlessness at rest"],category:"Safety",duration:"7 min"},
  { id:"action_plan",title:"Your COPD Action Plan",content:"Personalised plan for day-to-day management and worsening symptoms. Includes regular medications, exacerbation recognition, and when to seek emergency care.",keyPoints:["GREEN zone: stable — take regular meds","YELLOW zone: worsening — increase reliever","RED zone: severe — call emergency","Keep plan visible, share with family","Update at every follow-up"],category:"Safety",duration:"4 min"},
  { id:"oxygen_therapy",title:"Oxygen Therapy in COPD",content:"LTOT improves survival in chronic severe hypoxaemia. Use ≥15 hours/day. IMPORTANT: Target SpO₂ is 88-92% — too much oxygen can cause CO₂ retention.",keyPoints:["LTOT improves SURVIVAL (NOTT/MRC trials)","Use ≥15 hours/day","Target SpO₂ 88-92% in COPD","High-flow O₂ can cause CO₂ retention","NO SMOKING near oxygen"],category:"Treatment",duration:"6 min"},
  { id:"nutrition_copd",title:"Nutrition and COPD",content:"COPD increases resting energy expenditure by 30-50%. Good nutrition supports respiratory muscles and immune system.",keyPoints:["Eat small frequent meals","High protein for respiratory muscles","Keep BMI 21-25","Vitamin D if deficient","Stay hydrated for thinner mucus"],category:"Lifestyle",duration:"4 min"},
  { id:"exercise_copd",title:"Exercise with COPD",content:"Exercise is safe and beneficial. Improves cardiovascular fitness and breathing muscle strength. Start slowly and build up.",keyPoints:["Aim for 150 min moderate exercise/week","Walking is best for COPD","Both aerobic + strength training","Use reliever inhaler 15 min before exercise","Paced breathing during exercise"],category:"Lifestyle",duration:"5 min"},
  { id:"vaccinations",title:"Vaccinations for COPD",content:"All COPD patients need: annual influenza, pneumococcal, COVID-19, and Tdap vaccines. Vaccinations significantly reduce infection-triggered exacerbations.",keyPoints:["Influenza: annual — reduces exacerbations 30-40%","Pneumococcal: PCV20 or PCV15+PPSV23","COVID-19: stay up to date","Tdap: every 10 years","Vaccinations prevent exacerbation triggers"],category:"Prevention",duration:"3 min"},
  { id:"advance_care",title:"Advance Care Planning",content:"Discuss your wishes for future care when well. Includes advance directives, healthcare proxy, and preferences for ventilation and palliative care.",keyPoints:["Not giving up — taking control","Discuss values with family and doctor","Complete advance directive","Choose a healthcare proxy","Palliative care alongside active treatment"],category:"Planning",duration:"6 min"},
];

