function ComplicationsTab({complications,onToggle}:{complications:Complication[];onToggle:(name:string)=>void}){const INFO:Record<string,string>= {"Pulmonary Hypertension":"Pulmonary artery pressure >20 mmHg. Target O₂ 88-92%, consider vasodilators.","Cor Pulmonale":"Right heart failure from lung disease. Optimise LTOT, diuretics, echo monitoring.","Respiratory Failure (Type I)":"Hypoxaemic (PaO₂ <60). LTOT evaluation.","Respiratory Failure (Type II)":"Hypercapnic (PaCO₂ >45). Consider NIV, LTOT with caution.","Secondary Polycythaemia":"Hb/Hct ↑ from chronic hypoxaemia. LTOT is treatment.","Cachexia":"Weight loss from ↑ work of breathing. Nutritional support, appetite stimulants.","Osteoporosis (steroid-related)":"DEXA scan, calcium/vitamin D, bisphosphonates if indicated.","Anxiety/Depression":"Screen with PHQ-9/GAD-7. CBT, SSRIs, pulmonary rehab.","Pneumonia":"↑ Risk in COPD. Vaccinate. Chest X-ray, antibiotics per CURB-65.","Bronchiectasis":"CT confirmed. Sputum clearance, airway clearance devices.","Lung Cancer (↑ risk)":"Screen with LDCT annually if eligible.","Pneumothorax":"Spontaneous in COPD. Needle decompression or chest tube.","Atrial Fibrillation":"Rate/rhythm control. CHA₂DS₂-VASc for anticoagulation.","Right Heart Failure":"Signs: JVD, peripheral oedema, hepatomegaly. Diuretics + LTOT.","OSA Overlap Syndrome":"OSA + COPD. Auto-CPAP/BiPAP, LTOT if hypoxaemic."};return(<div><SectHeader label="COPD Complications" color={T.danger}/><div className="copd-comp-grid" style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:7}}>{COMPLICATIONS.map(c=>{const comp=complications.find(x=>x.name===c);return(<button key={c} onClick={()=>onToggle(c)} style={{border:`0.5px solid ${comp?"#fca5a5":T.border}`,borderRadius:10,padding:"10px 11px",background:comp?"#fef2f2":T.bg,cursor:"pointer",textAlign:"left",fontFamily:"inherit"}}><div style={{display:"flex",alignItems:"flex-start",gap:7}}><div style={{width:16,height:16,borderRadius:4,border:`1.5px solid ${comp?T.danger:T.border}`,background:comp?T.danger:"transparent",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,marginTop:1}}>{comp&&<span style={{color:"#fff",fontSize:9,lineHeight:1}}>✓</span>}</div><div><div style={{fontWeight:600,fontSize:12,color:comp?T.danger:T.text}}>{c}</div>{comp&&<div style={{color:T.faint,fontSize:10,marginTop:1}}>Dx: {comp.date}</div>}<div style={{color:T.faint,fontSize:10,marginTop:2,lineHeight:1.4}}>{INFO[c]}</div></div></div></button>)})}</div></div>);}
